// n8n-FIRST PROTOTYPE of the reward rule. The backend sends raw facts
// (targetMinutes + the set of days with a successful session) and the
// business rule — coins and streak — lives HERE, editable without a deploy.
// The migrated/hardened version of this exact rule is shared/src/derive.ts.
//
// Same idempotency guard as the production workflow: dedupe on sessionId.
const staticData = $getWorkflowStaticData('global');
if (!staticData.seenSessionIds) staticData.seenSessionIds = {};

const p = $input.first().json.body ?? $input.first().json;
const duplicate = p.sessionId in staticData.seenSessionIds;
if (!duplicate) staticData.seenSessionIds[p.sessionId] = Date.now();

// Rule 1: coins = 1 per target minute, minimum 1.
const coinsEarned = Math.max(1, Math.round(p.targetMinutes));

// Rule 2: streak = consecutive days with >= 1 success, counting back from
// today (a success-free today doesn't break yesterday's streak).
const days = new Set(p.completedDayKeys);
const shift = (dayKey, n) => {
  const [y, m, d] = dayKey.split('-').map(Number);
  const dt = new Date(y, m - 1, d + n);
  return `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, '0')}-${String(dt.getDate()).padStart(2, '0')}`;
};
let streakDays = 0;
let cursor = days.has(p.todayKey) ? p.todayKey : shift(p.todayKey, -1);
while (days.has(cursor)) {
  streakDays += 1;
  cursor = shift(cursor, -1);
}

return [{ json: { sessionId: p.sessionId, studentId: p.studentId, coinsEarned, streakDays, duplicate } }];
